'use strict';

// MODULES //

var tape = require( 'tape' );
var sentencize = require( './../lib' );


// TESTS //

tape( 'the function correctly handles multiple punctuation marks', function test( t ) {
        var expected;
        var actual;
        var str;

        // Test with multiple exclamation marks
        str = 'Hello World!! How are you?';
        expected = [ 'Hello World!!', 'How are you?' ];
        actual = sentencize( str );
        t.deepEqual( actual, expected, 'correctly handles multiple exclamation marks' );

        // Test with mixed punctuation marks
        str = 'Hello World!? How are you?';
        expected = [ 'Hello World!?', 'How are you?' ];
        actual = sentencize( str );
        t.deepEqual( actual, expected, 'correctly handles mixed punctuation marks' );

        // Test with multiple question marks
        str = 'Hello World?? How are you?';
        expected = [ 'Hello World??', 'How are you?' ];
        actual = sentencize( str );
        t.deepEqual( actual, expected, 'correctly handles multiple question marks' );

        // Test with multiple periods followed by other marks
        str = 'Hello World..! How are you?';
        expected = [ 'Hello World..!', 'How are you?' ];
        actual = sentencize( str );
        t.deepEqual( actual, expected, 'correctly handles periods followed by other marks' );

        // Test with multiple sentences with multiple punctuation marks
        str = 'Hello World!! How are you?? I am fine!!';
        expected = [ 'Hello World!!', 'How are you??', 'I am fine!!' ];
        actual = sentencize( str );
        t.deepEqual( actual, expected, 'correctly handles multiple sentences with multiple punctuation marks' );

        t.end();
});